// Serial Ports
package analogmodem

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40033/idl"
	"github.com/arminguenther/xeruspower-go/v40033/idl/event"
)

// Error codes
const (
	SUCCESS           int32 = 0 // No error
	ERR_INVALID_VALUE int32 = 1 // Invalid argument
)

// Interface for communication with an analog modem attached
// to a serial port
type AnalogModem interface {
	idl.Object

	// Get modem settings
	//
	//	@return -- Current modem settings
	GetSettings(ctx context.Context) (Settings, error)

	// Set modem settings
	//
	//	@param settings -- New settings
	//
	//	@return SUCCESS           -- on success
	//	@return ERR_INVALID_VALUE -- if any passed value was invalid
	SetSettings(ctx context.Context, settings Settings) (int32, error)
}

type Settings struct {
	DialInEnabled    bool  // Whether dial-in to device is enabled
	RingsUntilAnswer int32 // Number of rings until incoming call is answered
}

// Dial-in event
type DialInEvent interface {
	event.Event
	Number() string // The caller's phone number
	isDialInEvent()
}

// An event that's emitted when a dial-in call was answered
type CallReceivedEvent interface {
	DialInEvent
	isCallReceivedEvent()
}

// An event that's emitted when a dial-in call was hung up
type CallEndedEvent interface {
	DialInEvent
	// If true, the call was disconnected by the caller
	// If false, the call was disconnected locally,
	// e.g. due to a connection failure
	DisconnectedRemotely() bool
	isCallEndedEvent()
}
